const item = $input.first().json;
let text = (item.output != null ? String(item.output) : item.text || item.message || item.reply || item.result || '').trim();
if (typeof text !== 'string') text = '';
let payment_method = null, delivery_address = null, order_summary = null;
const dataMatch = text.match(/\nDATA:\s*(\{[\s\S]*\})\s*$/m);
if (dataMatch) {
  try {
    const data = JSON.parse(dataMatch[1]);
    payment_method = data.payment_method || null;
    delivery_address = data.delivery_address || null;
    order_summary = data.order_summary || (data.order_items && data.order_total ? { items: data.order_items, total: data.order_total } : null);
    text = text.replace(/\nDATA:\s*\{[\s\S]*\}\s*$/m, '').trim();
  } catch (e) {}
}
text = text.replace(/#/g, '').replace(/---/g, '').replace(/\n{4}/g, '\n\n').trim();
return [{ json: { message: text, payment_method, delivery_address, order_summary } }];
